const data = ($input.first().json?.data || $input.first().json) || {};

const patientId = `PT-${Date.now().toString(36).toUpperCase()}`;

let age = 'N/A';
if (data.dateOfBirth) {
  const dob = new Date(data.dateOfBirth);
  const today = new Date();
  age = Math.floor((today - dob) / (365.25 * 24 * 60 * 60 * 1000));
}

const criticalAllergens = ['penicillin', 'sulfa', 'latex', 'iodine', 'aspirin', 'nsaid'];
const allergiesStr = (data.allergiesList || '').toLowerCase();
const hasCriticalAllergy = criticalAllergens.some(c => allergiesStr.includes(c));

const insuranceSummary = data.insuranceProvider
  ? `${data.insuranceProvider} - ${data.policyNumber || 'N/A'}`
  : 'Self-Pay';

return [{ json: {
  patientId,
  fullName:             `${data.firstName || ''} ${data.lastName || ''}`.trim() || 'Unknown',
  dateOfBirth:          data.dateOfBirth          || 'N/A',
  gender:               data.gender               || 'N/A',
  phone:                data.phone                || 'N/A',
  email:                data.email                || 'N/A',
  address:              data.address              || 'N/A',
  age,
  insuranceSummary,
  medicalConditions:    data.medicalConditions    || 'None reported',
  currentMedications:   data.currentMedications   || 'None reported',
  allergiesList:        data.allergiesList         || 'NKDA',
  emergencyContactName: data.emergencyContactName || 'N/A',
  emergencyContactPhone: data.emergencyContactPhone || 'N/A',
  reasonForVisit:       data.reasonForVisit       || 'Not specified',
  hasCriticalAllergy,
  processedAt: new Date().toISOString()
}}];

